import { useState, useEffect, useRef } from "react";
import Sidebar from "../components/Sidebar";
import api from "../api/axios";
import { Send } from "lucide-react";
import { useAuth } from "../context/AuthContext";

export default function ChatPreview() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [sessionToken, setSessionToken] = useState(null);
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);
  const { user } = useAuth();

  useEffect(() => {
    setMessages([
      {
        role: "assistant",
        content: "Hello! I am your clinic assistant. How can I help you today?",
      },
    ]);
  }, []);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);
  const sendMessage = async () => {
  if (!input.trim() || loading) return;

  const userMessage = input.trim();
  setInput("");
  setMessages((prev) => [
    ...prev,
    { role: "user", content: userMessage },
  ]);
  setLoading(true);

  try {
    const storedUser = JSON.parse(localStorage.getItem("user") || "{}");
    const slug =
      user?.tenant_slug ||
      storedUser?.tenant_slug ||
      storedUser?.tenant_id ||
      "city-clinic";

    // DEBUG — check all values
    console.log("=== CHAT DEBUG ===");
    console.log("user from context:", user);
    console.log("storedUser from localStorage:", storedUser);
    console.log("slug being used:", slug);
    console.log("API baseURL:", api.defaults.baseURL);
    console.log("==================");

    const res = await api.post("/chat/message", {
      message: userMessage,
      tenant_slug: slug,
      session_token: sessionToken || null,
    });

    console.log("Response received:", res.data);

    setSessionToken(res.data.session_token);
    setMessages((prev) => [
      ...prev,
      { role: "assistant", content: res.data.reply },
    ]);
  } catch (err) {
    console.log("=== ERROR DEBUG ===");
    console.log("Error status:", err.response?.status);
    console.log("Error detail:", err.response?.data);
    console.log("Request URL:", err.config?.url);
    console.log("Request baseURL:", err.config?.baseURL);
    console.log("Request payload:", err.config?.data);
    console.log("==================");

    setMessages((prev) => [
      ...prev,
      {
        role: "assistant",
        content: "Sorry, something went wrong. Please try again.",
      },
    ]);
  } finally {
    setLoading(false);
  }
};

//   const sendMessage = async () => {
//   if (!input.trim() || loading) return;

//   const userMessage = input.trim();
//   setInput("");
//   setMessages((prev) => [
//     ...prev,
//     { role: "user", content: userMessage },
//   ]);
//   setLoading(true);

//   try {
//     // Get tenant_slug from multiple sources
//     const storedUser = JSON.parse(localStorage.getItem("user") || "{}");
//     const slug = 
//       user?.tenant_slug || 
//       storedUser?.tenant_slug || 
//       storedUser?.tenant_id ||
//       "rimshaclinic";

//     console.log("=== CHAT DEBUG ===");
//     console.log("user from context:", user);
//     console.log("storedUser from localStorage:", storedUser);
//     console.log("slug being used:", slug);
//     console.log("API baseURL:", api.defaults.baseURL);
//     console.log("==================");

//     const res = await api.post("/chat/message", {
//       message: userMessage,
//       tenant_slug: slug,
//       session_token: sessionToken || null,
//     });
//     console.log("Response received:", res.data);

//     setSessionToken(res.data.session_token);
//     setMessages((prev) => [
//       ...prev,
//       { role: "assistant", content: res.data.reply },
//     ]);
//   } catch (err) {
//     setMessages((prev) => [
//       ...prev,
//       {
//         role: "assistant",
//         content: "Sorry, something went wrong. Please try again.",
//       },
//     ]);
//   } finally {
//     setLoading(false);
//   }
// };

  const handleKeyDown = (e) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <div style={styles.layout}>
      <Sidebar />
      <div style={styles.main}>
        <h1 style={styles.heading}>Chat Preview</h1>
        <p style={styles.subtitle}>
          Test your chatbot exactly as patients will see it
        </p>

        <div style={styles.chatContainer}>
          <div style={styles.chatHeader}>
            <div style={styles.avatar}>🏥</div>
            <div>
              <p style={styles.botName}>ClinicBot</p>
              <p style={styles.botStatus}>● Online</p>
            </div>
          </div>

          <div style={styles.messages}>
            {messages.map((msg, i) => (
              <div
                key={i}
                style={
                  msg.role === "user"
                    ? styles.userBubbleWrap
                    : styles.botBubbleWrap
                }
              >
                <div
                  style={
                    msg.role === "user"
                      ? styles.userBubble
                      : styles.botBubble
                  }
                >
                  {msg.content}
                </div>
              </div>
            ))}
            {loading && (
              <div style={styles.botBubbleWrap}>
                <div style={styles.botBubble}>Typing...</div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>

          <div style={styles.inputArea}>
            <input
              style={styles.input}
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Type a message..."
              disabled={loading}
            />
            <button
              onClick={sendMessage}
              style={loading ? styles.sendButtonDisabled : styles.sendButton}
              disabled={loading}
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      </div>
    </div>
